// Buscar el archivo de empleados que corresponda a la empresa
// Ej: "empleados_QR.xlsx", "empleados_qr.xlsx", "QR_empleados.xlsx", "QR.xlsx"

const empresa = $('Configuracion').first().json.empresa || 'QR';
const empresaLower = empresa.toLowerCase();

const normalize = s => (s || '').toString()
  .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
  .toLowerCase();

let match = null;

for (const item of items) {
  const name = normalize(item.json.name || '');

  // Solo archivos xlsx/xls
  if (!name.endsWith('.xlsx') && !name.endsWith('.xls')) continue;

  // Buscar empresa en el nombre del archivo
  if (name.includes(empresaLower)) {
    match = item;
    break;
  }
}

if (!match) {
  const available = items.map(i => i.json.name).join(', ');
  throw new Error(
    `No se encontró archivo de empleados para empresa "${empresa}" en la carpeta.\n` +
    `Archivos disponibles: ${available}\n` +
    `El archivo debe contener "${empresa}" en su nombre (ej: empleados_${empresa}.xlsx)`
  );
}

console.log(`Archivo encontrado: ${match.json.name} (empresa: ${empresa})`);
return [match];

// =====================
// Helpers
// =====================
const clean = s => {
  const t = (s ?? '').toString().trim();
  const lo = t.toLowerCase();
  return ['empty','-','null','n/a'].includes(lo) ? '' : t;
};
const norm = s =>
  clean(s).normalize('NFD').replace(/[\u0300-\u036f]/g,'').toLowerCase();
const toDigits = s => clean(s).replace(/\D/g,'');

// Número robusto (último . o , como decimal)
const toNum = v => {
  let s = clean(v);
  if (!s) return 0;
  s = s.replace(/[^\d.,-]/g, '');
  const lc = s.lastIndexOf(','), ld = s.lastIndexOf('.');
  if (lc > ld || ld > lc) {
    const i = Math.max(lc, ld);
    const intPart  = s.slice(0, i).replace(/[^\d-]/g, '');
    const fracPart = s.slice(i + 1).replace(/[^\d]/g, '');
    s = intPart + (fracPart ? '.' + fracPart : '');
  } else {
    s = s.replace(/[^\d-]/g, '');
  }
  const n = Number(s);
  return Number.isFinite(n) ? n : 0;
};

const toBool = v => {
  if (v === null || v === undefined) return false;
  if (typeof v === 'boolean') return v;
  const s = norm(v);
  if (['1','si','sí','s','y','yes','true','verdadero','x','on','t'].includes(s)) return true;
  if (['0','no','n','false','f','off'].includes(s)) return false;
  const n = Number(v);
  return !isNaN(n) ? n > 0 : !!s;
};

// Excel serial -> ISO (YYYY-MM-DD)
const excelSerialToISO = d => {
  const n = Number(d);
  if (!isFinite(n) || n <= 0) return '';
  const base = Date.UTC(1899, 11, 30); // epoch Excel
  const dt = new Date(base + Math.floor(n) * 86400000);
  return isNaN(dt.getTime()) ? '' : dt.toISOString().slice(0,10);
};

// Fecha robusta: serial Excel, dd/mm/aaaa, dd-mm-aaaa, dd.mm.aaaa, ISO
const toISO = v => {
  if (v === null || v === undefined || v === '') return '';
  const asNum = Number(v);
  if (!isNaN(asNum) && clean(v).match(/^\d+(\.0+)?$/)) return excelSerialToISO(asNum);
  let s = clean(v).replace(/[.]/g,'/').replace(/-/g,'/');
  const m = s.match(/^(\d{1,2})\/(\d{1,2})\/(\d{2,4})$/);
  if (m) {
    let [_, d, mo, y] = m;
    if (y.length === 2) y = String(2000 + Number(y));
    return `${y.padStart(4,'0')}-${mo.padStart(2,'0')}-${d.padStart(2,'0')}`;
  }
  const dt = new Date(s);
  return isNaN(dt.getTime()) ? '' : dt.toISOString().slice(0,10);
};

const mapEstado = v => {
  const s = norm(v);
  if (s === '' || s === 'activo' || ['act','a'].includes(s)) return 'activo';
  if (['inactivo','baja','retirado','desvinculado','pasivo','ina','p'].includes(s)) return 'inactivo';
  return 'activo';
};

// =====================
// Sinónimos de columnas
// =====================
const syn = {
  identificacion: ['identificacion','cédula','cedula','ci','dni','id','nro cedula','numero cedula','número cédula'],
  nombre: ['nombre','apellidos y nombres','empleado','colaborador'],
  fecha_nacimiento: ['fecha_nacimiento','fecha nacimiento','f_nacimiento','nacimiento'],
  direccion: ['direccion','dirección'],
  telefono: ['telefono','teléfono'],
  email: ['email','correo','correo_electronico','correo electrónico'],
  fecha_contratacion: ['fecha_contratacion','fecha ingreso','fecha contrato','fecha_contrato','ingreso'],
  salario_base: ['salario_base','sueldo','sueldo_base','salario base','sueldo base'],
  decimos_mensual: ['decimos_mensual','decimos mensual','mensualizacion decimos','paga decimos mensual','acumula decimos'],
  estado: ['estado','estatus','status'],
  fecha_salida: ['fecha_salida','fecha salida','baja'],
  id_banco: ['id_banco','banco_id','banco'],
  cuenta_bancaria: ['cuenta_bancaria','cuenta','numero cuenta','numero_cuenta','nro cuenta','número de cuenta','número_cuenta','num cuenta'],
  id_cargo: ['id_cargo','cargo_id','cargo'],
  contacto_emergencia: ['contacto_emergencia','contacto emergencia','contacto de emergencia','emergencia'],
  codigo_empresa: ['codigo_empresa','empresa','cod empresa','codigo emp','codigo','código'],
  sueldo_variable: ['sueldo_variable'],
  transporte: ['transporte'],
  movilizacion: ['movilizacion','movilización'],
  valor_alimentacion_4_5: ['valor_alimentacion_4_5','alimentacion_4_5','alimentación_4_5','usa 4.5 alimentacion'],
  compensacion: ['compensacion','compensación'],
  utilidades: ['utilidades'],
  otros_ingresos: ['otros_ingresos','otros ingresos','ingresos otros'],
  anticipos: ['anticipos','anticipo'],
  prestamos_empresa: ['prestamos_empresa','prestamos','préstamos empresa','prestamos empresa'],
  iess_quirograficos: ['iess_quirograficos','iess_quirografarios','iess quirografario','quirografario iess'],
  crediflash: ['crediflash','credi flash','credi_flash'],
  saludsa: ['saludsa','seguro_salud','seguro salud'],
};

const pickKey = (obj, names) => {
  const keys = Object.keys(obj);
  for (const nm of names) {
    const k = keys.find(k => norm(k) === norm(nm));
    if (k) return k;
  }
  return null;
};

// =====================
// Normalización → 1 item por empleado
// =====================
const rows = items.map(i => i.json || {});
const meta = ($('Configuracion').first().json) || {};
const out = [];

for (const row0 of rows) {
  const row = { ...row0 };

  // claves mínimas
  const kId  = pickKey(row, syn.identificacion);
  const kNom = pickKey(row, syn.nombre);
  const id   = kId  ? toDigits(row[kId]) : '';
  const nom  = kNom ? clean(row[kNom])   : '';
  if (!id || !nom) continue;

  // empresa visible y espejo en codigo_empresa
  const empresaVal = clean(row[pickKey(row, syn.codigo_empresa)] || meta.empresa || 'QR');

  const emp = {
    empresa: empresaVal,
    codigo_empresa: empresaVal,

    identificacion: id,
    nombre: nom,

    direccion: clean(row[pickKey(row, syn.direccion)] || ''),
    telefono: clean(row[pickKey(row, syn.telefono)] || ''),
    email: clean(row[pickKey(row, syn.email)] || ''),
    cuenta_bancaria: clean(row[pickKey(row, syn.cuenta_bancaria)] || ''),
    contacto_emergencia: clean(row[pickKey(row, syn.contacto_emergencia)] || ''),

    estado: mapEstado(row[pickKey(row, syn.estado)] ?? 'activo'),

    fecha_nacimiento:   toISO(row[pickKey(row, syn.fecha_nacimiento)]   ?? ''),
    fecha_contratacion: toISO(row[pickKey(row, syn.fecha_contratacion)] ?? ''),
    fecha_salida:       toISO(row[pickKey(row, syn.fecha_salida)]       ?? ''),

    salario_base:        toNum(row[pickKey(row, syn.salario_base)]        ?? 0),
    sueldo_variable:     toNum(row[pickKey(row, syn.sueldo_variable)]     ?? 0),
    transporte:          toNum(row[pickKey(row, syn.transporte)]          ?? 0),
    movilizacion:        toNum(row[pickKey(row, syn.movilizacion)]        ?? 0),
    compensacion:        toNum(row[pickKey(row, syn.compensacion)]        ?? 0),
    utilidades:          toNum(row[pickKey(row, syn.utilidades)]          ?? 0),
    otros_ingresos:      toNum(row[pickKey(row, syn.otros_ingresos)]      ?? 0),
    anticipos:           toNum(row[pickKey(row, syn.anticipos)]           ?? 0),
    prestamos_empresa:   toNum(row[pickKey(row, syn.prestamos_empresa)]   ?? 0),
    iess_quirograficos:  toNum(row[pickKey(row, syn.iess_quirograficos)]  ?? 0),
    crediflash:          toNum(row[pickKey(row, syn.crediflash)]          ?? 0),
    saludsa:             toNum(row[pickKey(row, syn.saludsa)]             ?? 0),

    decimos_mensual:         toBool(row[pickKey(row, syn.decimos_mensual)]        ?? 1),
    valor_alimentacion_4_5:  toBool(row[pickKey(row, syn.valor_alimentacion_4_5)] ?? 1),

    id_banco: null,
    id_cargo: null,
  };

  // ids opcionales numéricos
  const kb = pickKey(row, syn.id_banco);
  const kc = pickKey(row, syn.id_cargo);
  if (kb && clean(row[kb]) !== '') emp.id_banco = Number(row[kb]);
  if (kc && clean(row[kc]) !== '') emp.id_cargo = Number(row[kc]);

  out.push({ json: emp });
}

return out;
